var body = $input.first().json.body || $input.first().json;

if (!body.tenantId) {
  throw new Error('tenantId is required');
}

function esc(v) { return v == null ? 'NULL' : "'" + String(v).replace(/'/g, "''") + "'"; }

var typeEvenements = body.typeEvenements || null;

var baseWhere = "WHERE tenant_id = " + esc(body.tenantId) + "::uuid";
if (typeEvenements) {
  var events = typeEvenements.split(',').map(function(e) { return esc(e.trim()); }).join(',');
  baseWhere += " AND type_evenement IN (" + events + ")";
}

return [{ json: {
  tenantId: body.tenantId,
  baseWhere: baseWhere
} }];

var totalResult = $('05. Count Total').first().json;
var succeededResult = $('06. Count Succeeded').first().json;
var errorsResult = $('07. Count Errors').first().json;
var pendingResult = $('08. Count Pending').first().json;
var byEventData = $('09. Count By Workflow').all().map(function(item) { return item.json; }).filter(function(i) { return i.type_evenement; });

var leadEvents = ['lead_create','lead_created','lead_update','lead_updated','lead_delete','lead_deleted','lead_questionnaire','lead_entretien','lead_confirmation','lead_inscription','leads_list','lead_get','lead_update_status','lead_status_updated'];
var clientEvents = ['client.created','client.updated','client.deleted','client.onboarding','client_create','client_update','client_delete','client_create_from_lead','clients_list','client_get'];
var facturationEvents = ['invoice_create','invoice_send','invoice_paid','invoice_overdue','invoice_get','invoice_update','invoice_delete','invoice_generate_pdf','invoices_list','devis_list','devis_get','devis_create','devis_send','devis_accept','devis_convert_to_invoice','devis_convert_to_bdc','devis_update','devis_delete','bdc_list','bdc_get','bdc_create','bdc_update','bdc_validate','bdc_convert_to_invoice','bdc_delete','avoir_list','avoir_get','avoir_create','avoir_validate','avoir_delete','invoice_convert_to_avoir','proforma_list','proforma_get','proforma_create','proforma_send','proforma_accept','proforma_convert_to_invoice','proforma_delete'];
var abonnementsEvents = ['subscription_renewal','subscription_cancelled','subscription_suspended','subscription_upgrade','stripe_checkout_completed'];
var marketingEvents = ['marketing_post_create','marketing_post_publish','marketing_stats'];
var authEvents = ['password_reset_request','auth_login','auth_register'];
var articlesEvents = ['article_codes_list','article_code_create','article_code_update','article_code_delete'];
var telephonieEvents = ['call_log_list','call_log_get','call_log_stats','call_log_create','call_log_update','call_log_delete','twilio_config_get','twilio_config_update','twilio_test_call','twilio_outbound_call','sms_list','sms_stats','sms_send'];

var byWorkflow = {
  leads: { total: 0, errors: 0, succeeded: 0 },
  clients: { total: 0, errors: 0, succeeded: 0 },
  facturation: { total: 0, errors: 0, succeeded: 0 },
  abonnements: { total: 0, errors: 0, succeeded: 0 },
  marketing: { total: 0, errors: 0, succeeded: 0 },
  auth: { total: 0, errors: 0, succeeded: 0 },
  articles: { total: 0, errors: 0, succeeded: 0 },
  telephonie: { total: 0, errors: 0, succeeded: 0 }
};

byEventData.forEach(function(item) {
  var count = parseInt(item.count) || 0;
  if (leadEvents.indexOf(item.type_evenement) >= 0) { byWorkflow.leads.total += count; }
  else if (clientEvents.indexOf(item.type_evenement) >= 0) { byWorkflow.clients.total += count; }
  else if (facturationEvents.indexOf(item.type_evenement) >= 0) { byWorkflow.facturation.total += count; }
  else if (abonnementsEvents.indexOf(item.type_evenement) >= 0) { byWorkflow.abonnements.total += count; }
  else if (marketingEvents.indexOf(item.type_evenement) >= 0) { byWorkflow.marketing.total += count; }
  else if (authEvents.indexOf(item.type_evenement) >= 0) { byWorkflow.auth.total += count; }
  else if (articlesEvents.indexOf(item.type_evenement) >= 0) { byWorkflow.articles.total += count; }
  else if (telephonieEvents.indexOf(item.type_evenement) >= 0) { byWorkflow.telephonie.total += count; }
});

return [{ json: {
  total: parseInt(totalResult.total) || 0,
  succeeded: parseInt(succeededResult.succeeded) || 0,
  errors: parseInt(errorsResult.errors) || 0,
  enAttente: parseInt(pendingResult.en_attente) || 0,
  byWorkflow: byWorkflow
} }];
